import { describe, expect, it } from 'vitest';
import {
  codedBitLength,
  decodeFec,
  encodeFec,
  resolveFecProfile,
} from './fec-codec';
import { mulberry32 } from './noise';

const KEY = Uint8Array.from(
  'GNOSIS-RFKEY/1 prefixHash=66 prefixLen=7 boundaryDimension=12 stationCount=2 crc16=a4ce',
  (c) => c.charCodeAt(0),
);

describe('fec-codec', () => {
  it('rs+conv round-trips clean', () => {
    const p = resolveFecProfile('rs+conv');
    const coded = encodeFec(KEY, p);
    expect(coded.length).toBe(codedBitLength(KEY.length, p));
    const out = decodeFec(coded, p, KEY.length);
    expect(out.block).toEqual(KEY);
  });

  it('rs+conv recovers a coded burst + scatter that destroys the raw frame (A/B)', () => {
    const fec = resolveFecProfile('rs+conv');
    const none = resolveFecProfile('none');
    const rng = mulberry32(2026);

    const codedFec = encodeFec(KEY, fec);
    const codedRaw = encodeFec(KEY, none);

    // Same physical corruption pattern (proportional) on each: a burst + scatter.
    const corrupt = (bits: Uint8Array): Uint8Array => {
      const out = bits.slice();
      const burstStart = Math.floor(out.length * 0.3);
      for (let i = 0; i < 24 && burstStart + i < out.length; i++) out[burstStart + i] ^= 1;
      const scatter = Math.floor(out.length * 0.01);
      for (let i = 0; i < scatter; i++) {
        const pos = Math.floor(rng() * out.length);
        out[pos] ^= 1;
      }
      return out;
    };

    const fecOut = decodeFec(corrupt(codedFec), fec, KEY.length);
    expect(fecOut.block).toEqual(KEY); // FEC closes the gap

    const rawOut = decodeFec(corrupt(codedRaw), none, KEY.length);
    expect(rawOut.block).not.toEqual(KEY); // raw frame is destroyed
  });
});
